// ============================================================
// PARSE CONTENT JSON – V25.6
// Robuste JSON-Auswertung und Gesamtprüfung gegen den Source-Lock.
// Kurze Einzeltexte werden nicht mehr wegen eines fehlenden Wortlauts blockiert.
// ============================================================

function safeStr(value) {
  return value === null || value === undefined ? '' : String(value).trim();
}

function parseObject(value) {
  if (!value) return {};
  if (typeof value === 'object' && !Array.isArray(value)) return value;
  try {
    const parsed = JSON.parse(String(value));
    return parsed && typeof parsed === 'object' && !Array.isArray(parsed) ? parsed : {};
  } catch (e) {
    return {};
  }
}

function asArray(value) {
  if (Array.isArray(value)) {
    return value.map(v => safeStr(v)).filter(Boolean);
  }
  if (typeof value === 'string' && value.trim()) {
    const text = value.trim();
    try {
      const parsed = JSON.parse(text);
      if (Array.isArray(parsed)) return parsed.map(v => safeStr(v)).filter(Boolean);
    } catch (e) {}
    return text.split(/\s*\|\s*|\s*;\s*|\r?\n+/).map(v => safeStr(v)).filter(Boolean);
  }
  return [];
}

function isUsable(value) {
  if (value === null || value === undefined) return false;
  if (typeof value === 'object' && !Array.isArray(value)) return Object.keys(value).length > 0;
  const text = safeStr(value);
  return text !== '' && text !== '{}' && text !== '[]' && text !== 'null' && text !== 'undefined';
}

function firstUsable(...values) {
  for (const value of values) if (isUsable(value)) return value;
  return '';
}

function extractJson(text) {
  if (!text) return null;
  const stripped = String(text)
    .replace(/^```(?:json)?\s*/i, '')
    .replace(/\s*```\s*$/i, '')
    .trim();
  const start = stripped.indexOf('{');
  const end = stripped.lastIndexOf('}');
  if (start === -1 || end === -1 || end <= start) return null;
  return stripped.slice(start, end + 1);
}

function getAiText(item) {
  const j = item?.json || {};
  if (Array.isArray(j.output) && j.output[0]?.content?.[0]?.text) return String(j.output[0].content[0].text);
  if (typeof j.output_text === 'string') return j.output_text;
  if (typeof j.text === 'string') return j.text;
  if (typeof j.message?.content === 'string') return j.message.content;
  if (Array.isArray(j.choices) && typeof j.choices[0]?.message?.content === 'string') return j.choices[0].message.content;
  if (Array.isArray(j.content)) {
    return j.content.map(entry => entry?.text || entry?.content || '').filter(Boolean).join('\n');
  }
  return '';
}

function getNodeItems(nodeName) {
  try {
    const items = $(nodeName).all(0, $runIndex);
    return Array.isArray(items) ? items : [];
  } catch (e) {
    return [];
  }
}

function getNodeRow(nodeName, expectedKey) {
  const items = getNodeItems(nodeName);
  if (!items.length) return {};
  if (expectedKey) {
    const found = items.find(item => safeStr(item?.json?.vorgangKey) === expectedKey);
    if (found?.json) return found.json;
  }
  return items[0]?.json || {};
}

function normDE(value) {
  return safeStr(value)
    .toLowerCase()
    .replace(/ä/g, 'ae').replace(/ö/g, 'oe').replace(/ü/g, 'ue').replace(/ß/g, 'ss')
    .replace(/[^a-z0-9]+/g, ' ')
    .replace(/\s+/g, ' ')
    .trim();
}

const STOP = new Set([
  'aber','alle','alles','auch','auf','aus','bei','das','dass','dem','den','der','des','die','dies','diese',
  'einem','einen','einer','eine','eines','fuer','gegen','haben','hier','ihre','ihren','ist','kann','mit','nach',
  'nicht','oder','sich','sind','soll','sollen','sowie','ueber','und','vom','von','vor','werden','wird','zur','zum'
]);

function tokens(value) {
  return normDE(value).split(/\s+/).filter(token => token.length >= 4 && !STOP.has(token));
}

function stem(token) {
  const t = normDE(token).replace(/\s/g, '');
  return t.length <= 5 ? t : t.substring(0, Math.max(5, Math.floor(t.length * 0.75)));
}

function containsTerm(text, term) {
  const nt = normDE(text);
  const nq = normDE(term);
  if (!nt || !nq) return false;
  if (nt.includes(nq)) return true;
  const compactText = nt.replace(/\s+/g, '');
  const compactTerm = nq.replace(/\s+/g, '');
  if (compactTerm.length >= 5 && compactText.includes(compactTerm)) return true;
  const tt = tokens(text);
  const qt = tokens(term);
  if (!tt.length || !qt.length) return false;
  return qt.some(q => {
    const qs = stem(q);
    return tt.some(t => {
      const ts = stem(t);
      return t === q || ts === qs || (qs.length >= 5 && t.includes(qs)) || (ts.length >= 5 && q.includes(ts));
    });
  });
}

function relatedToAnchor(text, anchor) {
  const textTokens = tokens(text);
  const anchorTokens = tokens(anchor);
  if (!textTokens.length || !anchorTokens.length) return false;
  let matches = 0;
  for (const a of anchorTokens) {
    const as = stem(a);
    if (textTokens.some(t => t === a || stem(t) === as || (as.length >= 5 && t.includes(as)))) matches++;
  }
  return matches >= (anchorTokens.length >= 4 ? 2 : 1);
}

const item = $input.item;
const current = item?.json || {};
const initialKey = safeStr(current.vorgangKey);
const loop0 = getNodeRow('Loop Reaktions-Vorgänge', initialKey);
const ai0 = getNodeRow('Prepare AI Content Input', initialKey || safeStr(loop0.vorgangKey));
const expectedKey = safeStr(firstUsable(current.vorgangKey, ai0.vorgangKey, loop0.vorgangKey));
const loop = getNodeRow('Loop Reaktions-Vorgänge', expectedKey);
const aiInput = getNodeRow('Prepare AI Content Input', expectedKey);

const base = { ...loop, ...aiInput, ...current };
base.vorgangKey = safeStr(firstUsable(current.vorgangKey, aiInput.vorgangKey, loop.vorgangKey));
base.vorgangsnummer = safeStr(firstUsable(current.vorgangsnummer, aiInput.vorgangsnummer, loop.vorgangsnummer));
base.title = safeStr(firstUsable(current.title, aiInput.title, loop.title));
base.analysisJson = firstUsable(current.analysisJson, aiInput.analysisJson, loop.analysisJson, '{}');
base.summaryText = safeStr(firstUsable(current.summaryText, aiInput.summaryText, loop.summaryText));
base.combinedText = safeStr(firstUsable(current.combinedText, aiInput.combinedText, loop.combinedText));

const rawText = getAiText(item);
const jsonString = extractJson(rawText);
let c = null;
let parseReason = '';
if (!jsonString) {
  parseReason = rawText ? 'Kein vollständiges JSON-Objekt in der AI-Ausgabe gefunden' : 'AI lieferte keine verwertbare Content-Ausgabe';
} else {
  try { c = JSON.parse(jsonString); }
  catch (e) { parseReason = 'AI-Ausgabe konnte nicht als gültiges Content-JSON verarbeitet werden: ' + e.message; }
}

if (!c || typeof c !== 'object' || Array.isArray(c)) {
  return [{ json: {
    ...base,
    contentParseError: true,
    contentValid: false,
    contentReady: false,
    contentValidationErrors: [parseReason || 'Ungültige Content-Ausgabe'],
    rawContentText: rawText,
    contentJson: JSON.stringify({ workflow: {
      contentValid: false,
      contentParseError: true,
      contentErrorReason: parseReason || 'Ungültige Content-Ausgabe',
      checkedAt: new Date().toISOString(),
      workflowVersion: 'content-v25.6-chain-status-fix'
    }}),
    websiteHeadline: '', websiteArticle: '', websiteSummaryShort: '', websiteTags: '[]',
    facebookPost: '', facebookHashtags: '[]', instagramCaption: '', instagramPost: '', instagramHashtags: '[]',
    pressStatement: '', dieParteiReaktion: '{}', headlines: '{}', kernbotschaft: '',
    belegbareFakten: JSON.stringify(asArray(base.belegbareFakten)),
    kritischeNachfrage: safeStr(base.kritischeNachfrage),
    offenePunkte: JSON.stringify(asArray(base.offenePunkte)),
    unsicherheitenSummary: safeStr(base.unsicherheitenSummary),
    status: 'content_error', visualStatus: 'blocked_by_content_error', visualNeeded: false,
    visualDecisionReason: parseReason || 'Ungültige Content-Ausgabe'
  }}];
}

// Identifikatoren niemals aus dem Modell übernehmen.
c.vorgangsnummer = base.vorgangsnummer;
c.vorgangKey = base.vorgangKey;

const websiteHeadline = safeStr(c.website?.headline);
const websiteArticle = safeStr(c.website?.article);
const websiteSummaryShort = safeStr(c.website?.summaryShort);
const websiteTags = asArray(c.website?.tags);
const facebookPost = safeStr(c.facebook?.post);
const facebookHashtags = asArray(c.facebook?.hashtags);
const instagramPost = safeStr(c.instagram?.post);
const instagramCaption = safeStr(firstUsable(c.instagram?.caption, instagramPost));
const instagramHashtags = asArray(c.instagram?.hashtags);
const dpr = parseObject(c.dieParteiReaktion);
const dprText = safeStr(dpr.text);
const absurdeForderung = safeStr(dpr.absurdeForderung);
const pressStatement = safeStr(c.pressStatement);
const headlines = parseObject(c.headlines);
const headlinesText = [headlines.sachlich, headlines.kritisch, headlines.satirisch].map(safeStr).filter(Boolean).join('\n');

const analysis = parseObject(base.analysisJson);
const sourceLock = parseObject(analysis.sourceLock);
const sourceLockValid = analysis.sourceLockValid === true || safeStr(analysis.sourceLockValid).toLowerCase() === 'true';
const sourceTopic = safeStr(sourceLock.sourceTopic);
const sourceConflict = safeStr(sourceLock.sourceConflict);
const requiredTerms = asArray(sourceLock.requiredTerms);
const GENERIC = new Set(['antrag','buerokratie','goslar','kommunalpolitik','politik','rathaus','stadt','verwaltung','vorlage','vorgang']);
const concreteTerms = requiredTerms.filter(term => {
  const n = normDE(term).replace(/\s+/g, '');
  return n.length >= 4 && !GENERIC.has(n);
});

const allContent = [
  c.kernbotschaft, websiteHeadline, websiteSummaryShort, websiteArticle, facebookPost,
  instagramPost, instagramCaption, dprText, absurdeForderung, pressStatement, headlinesText,
  c.kritischeNachfrage, asArray(c.belegbareFakten).join(' '), asArray(c.offenePunkte).join(' ')
].map(safeStr).filter(Boolean).join('\n');

const errors = [];
if (!sourceLockValid) errors.push('analysisJson.sourceLockValid ist nicht true');
if (!sourceTopic) errors.push('analysisJson.sourceLock.sourceTopic fehlt');
if (!sourceConflict) errors.push('analysisJson.sourceLock.sourceConflict fehlt');
if (requiredTerms.length < 2) errors.push('analysisJson.sourceLock.requiredTerms enthält weniger als 2 Begriffe');

const requiredTermFound = concreteTerms.some(term => containsTerm(allContent, term));
const sourceTopicFound = sourceTopic ? relatedToAnchor(allContent, sourceTopic) : false;
const sourceConflictFound = sourceConflict ? relatedToAnchor(allContent, sourceConflict) : false;
const overallSourceMatch = requiredTermFound || sourceTopicFound || sourceConflictFound;
if (errors.length === 0 && !overallSourceMatch) {
  errors.push('Gesamter Content enthält keinen erkennbaren Bezug zu sourceTopic, sourceConflict oder requiredTerms');
}

if (websiteHeadline.length < 5) errors.push('websiteHeadline fehlt oder ist zu kurz');
if (websiteArticle.length < 100) errors.push('websiteArticle fehlt oder ist zu kurz');
if (facebookPost.length < 80) errors.push('facebookPost fehlt oder ist zu kurz');
if (instagramCaption.length < 50) errors.push('instagramCaption fehlt oder ist zu kurz');

const contentValid = errors.length === 0;
const contentWithWorkflow = {
  ...c,
  workflow: {
    ...(c.workflow && typeof c.workflow === 'object' && !Array.isArray(c.workflow) ? c.workflow : {}),
    contentValid,
    contentParseError: false,
    contentValidationErrors: errors,
    sourceLockValidation: {
      canonicalSourceLockUsed: true,
      sourceLockValid,
      requiredTermsCount: requiredTerms.length,
      concreteRequiredTermsCount: concreteTerms.length,
      requiredTermFound,
      sourceTopicFound,
      sourceConflictFound,
      overallSourceMatch
    },
    checkedAt: new Date().toISOString(),
    workflowVersion: 'content-v25.6-chain-status-fix'
  }
};

return [{ json: {
  ...base,
  vorgangsnummer: base.vorgangsnummer,
  vorgangKey: base.vorgangKey,
  contentParseError: false,
  contentValid,
  contentReady: contentValid,
  contentValidationErrors: errors,
  rawContentText: contentValid ? '' : rawText,
  contentJson: JSON.stringify(contentWithWorkflow),
  kernbotschaft: safeStr(c.kernbotschaft),
  belegbareFakten: JSON.stringify(asArray(c.belegbareFakten).length ? asArray(c.belegbareFakten) : asArray(base.belegbareFakten)),
  kritischeNachfrage: safeStr(firstUsable(c.kritischeNachfrage, base.kritischeNachfrage)),
  offenePunkte: JSON.stringify(asArray(c.offenePunkte).length ? asArray(c.offenePunkte) : asArray(base.offenePunkte)),
  unsicherheitenSummary: safeStr(firstUsable(c.unsicherheitenSummary, base.unsicherheitenSummary)),
  websiteHeadline, websiteArticle, websiteSummaryShort, websiteTags: JSON.stringify(websiteTags),
  facebookPost, facebookHashtags: JSON.stringify(facebookHashtags),
  instagramPost, instagramCaption, instagramHashtags: JSON.stringify(instagramHashtags),
  dieParteiReaktion: JSON.stringify({ text: dprText, absurdeForderung }),
  pressStatement, headlines: JSON.stringify(headlines),
  status: contentValid ? 'content_generated' : 'content_error',
  visualStatus: contentValid ? (base.visualStatus === 'visual_topic_ok' ? 'needs_visual_prompt' : (safeStr(base.visualStatus) || 'waiting_for_content')) : 'blocked_by_content_error',
  visualNeeded: contentValid ? base.visualNeeded : false,
  visualDecisionReason: contentValid ? safeStr(base.visualDecisionReason) : 'Content unvollständig: ' + errors.join(' | ')
}}];

// ============================================================
// PREPARE VISUAL DECISION – v25.1 (SOURCE_LOCK_FIX)
// Gibt ein Bild erst nach vollständigem Content UND gültigem Source-Lock frei.
// Es werden ausschließlich vorhandene Datenbankfelder verwendet.
// FIX: j wird vor _resetImageFields definiert (ReferenceError-Fix)
// FIX: sourceLockValid-Prüfung vor Bildfreigabe
// ============================================================

function norm(v) {
  return String(v ?? '').trim().toUpperCase();
}
function safeStr(v) {
  return v === null || v === undefined ? '' : String(v).trim();
}
function bool(v) {
  if (v === true || v === 1) return true;
  if (v === false || v === 0 || v === null || v === undefined) return false;
  const s = String(v).trim().toLowerCase();
  return s === 'true' || s === '1' || s === 'yes';
}
function num(v) {
  const n = parseFloat(String(v ?? '0').replace(',', '.'));
  return Number.isFinite(n) ? n : 0;
}
function parseObject(v) {
  if (!v) return {};
  if (typeof v === 'object' && !Array.isArray(v)) return v;
  try {
    const parsed = JSON.parse(String(v));
    return parsed && typeof parsed === 'object' && !Array.isArray(parsed) ? parsed : {};
  } catch (e) {
    return {};
  }
}
function asArray(v) {
  if (Array.isArray(v)) return v.filter(Boolean).map(x => String(x).trim());
  if (!v) return [];
  try {
    const p = JSON.parse(String(v));
    return Array.isArray(p) ? p.filter(Boolean).map(x => String(x).trim()) : [];
  } catch (e) {
    return String(v).split(/\s*\|\s*/).filter(Boolean).map(x => x.trim());
  }
}
function firstValue(...values) {
  for (const value of values) {
    if (value === null || value === undefined) continue;
    if (Array.isArray(value) && value.length > 0) return value;
    if (typeof value === 'object' && !Array.isArray(value) && Object.keys(value).length > 0) return value;
    if (String(value).trim() !== '') return value;
  }
  return '';
}

// FIX 2.1: j muss VOR _resetImageFields definiert sein
const j = $input.item.json || {};

// ============================================================
// ALTLASTENENTWERTUNG: Alte Bildfelder zurücksetzen wenn neuer Content-Zyklus
// Verhindert Wiederverwendung veralteter Bildkonzepte nach neuer Analyse.
// Reset nur wenn Bild noch nicht fertiggestellt.
// ============================================================
// FIX: doneStates kannte bisher nur die finalen Bildstadien, nicht die
// P2-Zwischenstati (needs_visual_prompt/awaiting_headline_choice/headline_selected/...).
// Ein erneuter Lauf auf einer Zeile, die P2 (oder der Matrix-Headline-Leser) bereits
// weiterverarbeitet hat, hätte sonst bereits geposteten Headline-Kandidaten oder eine
// Leserauswahl in imageHeadline/imageSubline/visualJson stillschweigend geleert.
const P1_P2_ADVANCED_VISUAL_STATUS = [
  'needs_visual_prompt', 'awaiting_headline_choice', 'headline_selected',
  'visual_prompt_ready', 'visual_prompt_error', 'visual_prompt_topic_error',
  'blocked_by_source_lock', 'blocked_by_content_error', 'force_visual_reset',
  'image_generated', 'image_composed', 'matrix_posted', 'posted'
];
const visualStatusAlreadyAdvanced = P1_P2_ADVANCED_VISUAL_STATUS.includes(String(j.visualStatus || '').trim());
const _resetImageFields = !visualStatusAlreadyAdvanced;

// Kein Visual ohne belastbaren Content.
if (j.contentReady !== true || j.contentValid !== true || j.contentParseError === true) {
  const contentObj = parseObject(j.contentJson);
  const reason = 'Content-Gate nicht erfüllt';
  contentObj.workflow = {
    ...parseObject(contentObj.workflow),
    contentValid: false,
    visualReleased: false,
    visualReleaseReason: reason,
    visualReleaseCheckedAt: new Date().toISOString(),
    workflowVersion: 'content-v25.7-visual-status-repair-fix'
  };
  return [{
    json: {
      ...j,
      contentJson: JSON.stringify(contentObj),
      visualNeeded: false,
      visualStatus: 'blocked_by_content_error',
      visualDecisionReason: reason,
      status: 'content_error'
    }
  }];
}

const analysisObj = parseObject(j.analysisJson);
const contentObj = parseObject(j.contentJson);
const analysisAnchors = parseObject(analysisObj.visualAnchors);
const upstreamVisual = parseObject(analysisObj.visualWorkflow); // nur Diagnose; kein Sperrgrund mehr

// FIX 2.3: Canonical Source-Lock prüfen
const canonicalSourceLock = parseObject(analysisObj.sourceLock);
const sourceLockValid = bool(analysisObj.sourceLockValid);
const sourceLockErrors = [];

if (!sourceLockValid) {
  sourceLockErrors.push('analysisJson.sourceLockValid ist nicht true');
}
if (!canonicalSourceLock.sourceTopic) {
  sourceLockErrors.push('sourceLock.sourceTopic fehlt');
}
if (!canonicalSourceLock.sourceConflict) {
  sourceLockErrors.push('sourceLock.sourceConflict fehlt');
}
const canonicalRequiredTerms = asArray(canonicalSourceLock.requiredTerms);
if (canonicalRequiredTerms.length < 2) {
  sourceLockErrors.push('sourceLock.requiredTerms enthält weniger als 2 konkrete Begriffe');
}

// Wenn Source-Lock ungültig: Bildfreigabe blockieren
if (sourceLockErrors.length > 0) {
  const reason = 'Source-Lock ungültig: ' + sourceLockErrors.join(' | ');
  contentObj.workflow = {
    ...parseObject(contentObj.workflow),
    contentValid: true,
    visualReleased: false,
    visualReleaseReason: reason,
    visualReleaseCheckedAt: new Date().toISOString(),
    workflowVersion: 'content-v25.7-visual-status-repair-fix'
  };
  return [{
    json: {
      ...j,
      ...(_resetImageFields ? {
        imagePrompt: '',
        imageHeadline: '',
        imageSubline: '',
        imageNegativePrompt: '',
        visualJson: '{}'
      } : {}),
      contentJson: JSON.stringify(contentObj),
      contentValid: true,
      contentReady: true,
      visualNeeded: false,
      // FIX 2.3: blocked_by_source_lock darf von keinem Bildworkflow abgeholt werden
      // FIX: bereits fortgeschrittenen visualStatus (P2/Matrix-Headline-Leser) nicht zurückwerfen
      visualStatus: visualStatusAlreadyAdvanced ? String(j.visualStatus || '').trim() : 'blocked_by_source_lock',
      visualDecisionReason: visualStatusAlreadyAdvanced ? (safeStr(j.visualDecisionReason) || reason) : reason,
      status: 'content_generated'
    }
  }];
}

let sprengstoff = norm(firstValue(j.sprengstoff, analysisObj.sprengstoff));
let empfehlung = norm(firstValue(j.empfehlung, analysisObj.empfehlung));
let relevantScore = num(firstValue(j.relevantScore, analysisObj.relevantScore, analysisObj.relevanz));
let kommunikationspotenzial = num(firstValue(j.kommunikationspotenzial, analysisObj.kommunikationspotenzial));
// WICHTIG V25.7: Ein alter false-Wert aus der DataTable darf ein späteres true aus analysisJson/contentJson nicht überdecken.
// Daher OR-Logik statt firstValue(...). Sonst bleibt ein bildwürdiger Vorgang fälschlich ohne Sharepic.
let instagramCarouselNoetig = bool(j.instagramCarouselNoetig) || bool(analysisObj.instagramCarouselNoetig) || bool(contentObj.instagramCarouselNoetig);
// Roher Bedarf VOR der Source-Lock-/Anchor-Prüfung. Absichtlich NICHT instagramSharepicNoetig
// genannt, damit dieser Wert später nicht versehentlich mit der finalen Freigabe-Entscheidung
// (visualNeeded) verwechselt oder überschrieben wird.
let instagramSharepicAngefragt = bool(j.instagramSharepicNoetig) || bool(analysisObj.instagramSharepicNoetig) || bool(contentObj.instagramSharepicNoetig);

const anchors = {
  satireThemaKonkret: safeStr(firstValue(j.satireThemaKonkret, analysisAnchors.satireThemaKonkret, analysisObj.satireThemaKonkret)),
  satireKonfliktKonkret: safeStr(firstValue(j.satireKonfliktKonkret, analysisAnchors.satireKonfliktKonkret, analysisObj.satireKonfliktKonkret)),
  visualPflichtobjekte: asArray(firstValue(j.visualPflichtobjekte, analysisAnchors.visualPflichtobjekte, analysisObj.visualPflichtobjekte)),
  visualPflichthandlung: safeStr(firstValue(j.visualPflichthandlung, analysisAnchors.visualPflichthandlung, analysisObj.visualPflichthandlung)),
  visualBetroffene: asArray(firstValue(j.visualBetroffene, analysisAnchors.visualBetroffene, analysisObj.visualBetroffene)),
  visualOrt: safeStr(firstValue(j.visualOrt, analysisAnchors.visualOrt, analysisObj.visualOrt)),
  visualUeberzeichnung: safeStr(firstValue(j.visualUeberzeichnung, analysisAnchors.visualUeberzeichnung, analysisObj.visualUeberzeichnung)),
  visualErkennungssatz: safeStr(firstValue(j.visualErkennungssatz, analysisAnchors.visualErkennungssatz, analysisObj.visualErkennungssatz)),
  visualVerboteneErsatzmotive: asArray(firstValue(j.visualVerboteneErsatzmotive, analysisAnchors.visualVerboteneErsatzmotive, analysisObj.visualVerboteneErsatzmotive))
};

const reasons = [];
if (instagramCarouselNoetig) reasons.push('instagramCarouselNoetig=true');
if (instagramSharepicAngefragt) reasons.push('instagramSharepicNoetig=true');
if (empfehlung === 'REAGIEREN' && ['MITTEL', 'HOCH'].includes(sprengstoff)) {
  reasons.push('empfehlung=REAGIEREN+sprengstoff=' + sprengstoff);
}
if (relevantScore >= 8) reasons.push('relevantScore=' + relevantScore);
if (kommunikationspotenzial >= 8) reasons.push('kommunikationspotenzial=' + kommunikationspotenzial);

const visualRequested = reasons.length > 0;
const anchorErrors = [];
if (!anchors.satireThemaKonkret) anchorErrors.push('satireThemaKonkret fehlt');
if (!anchors.satireKonfliktKonkret) anchorErrors.push('satireKonfliktKonkret fehlt');
if (anchors.visualPflichtobjekte.length < 2) anchorErrors.push('mindestens zwei visualPflichtobjekte fehlen');
if (!anchors.visualPflichthandlung) anchorErrors.push('visualPflichthandlung fehlt');
if (!anchors.visualErkennungssatz) anchorErrors.push('visualErkennungssatz fehlt');
if (!anchors.visualUeberzeichnung) anchorErrors.push('visualUeberzeichnung fehlt');
if (anchors.visualVerboteneErsatzmotive.length < 2) anchorErrors.push('mindestens zwei visualVerboteneErsatzmotive fehlen');
if (!bool(analysisObj.visualAnchorsValid)) anchorErrors.push('analysisJson.visualAnchorsValid ist nicht true');
// FIX 2.3: requiredObjects und requiredAction aus canonicalSourceLock prüfen
if (!canonicalSourceLock.requiredAction) anchorErrors.push('sourceLock.requiredAction fehlt');
const canonicalRequiredObjects = asArray(canonicalSourceLock.requiredObjects);
