  current.text ??
  current.response ??
  current.result ??
  current.content ??
  '';

if (typeof text !== 'string') {
  text = JSON.stringify(text);
}

text = String(text || '')
  .replace(/\u0000/g, '')
  .replace(/[ \t]+/g, ' ')
  .replace(/\r\n/g, '\n')
  .replace(/\n{3,}/g, '\n\n')
  .trim();

const fileName =
  source.sourceFileName || source._fileName || source.name || source.filename ||
  current.sourceFileName || current.name || 'Dokument';

const filePath =
  source.sourceFilePath || source.nc_download_path || source.path ||
  current.sourceFilePath || current.nc_download_path || '';

const extractionOk = text.length > 80 &&
  !text.includes('Inhalt konnte nicht direkt extrahiert werden') &&
  !text.includes('Kein verwertbarer Text');

return [{
  json: {
    ...j,
    _fileName: fileName,
    _filePath: filePath,
    _extractedText: extractionOk ? text.substring(0, 50000) : '',
    extractionOk,
    extractedLength: text.length,
    extractionError: extractionOk ? '' : 'Kein verwertbarer Text aus Tika erhalten'
  }
}];

// Sortierung nach sachlicher ALLRIS-Reihenfolge:
// 1. Jahr aus Vorgangsnummer
// 2. Hauptnummer aus Vorgangsnummer
// 3. Folgenummer nach Bindestrich, z. B. 2026/196-01
// 4. volfdnr numerisch
// 5. firstseen als letzter Fallback
// 6. vorgangKey lexikografisch

function safe(v) {
  return v === null || v === undefined ? '' : String(v).trim();
}

function parseDate(v) {
  if (!v) return 0;
  const t = Date.parse(String(v));
  return Number.isFinite(t) ? t : 0;
}

function parseVolfdnr(v) {
  if (!v) return Infinity;
  const n = parseInt(String(v).replace(/[^0-9]/g, ''), 10);
  return Number.isFinite(n) ? n : Infinity;
}

function parseVorgangsnummer(v) {
  const s = safe(v);
  const m = s.match(/^(\d{4})\/(\d+)(?:-(\d+))?/);
  if (!m) return { year: Infinity, main: Infinity, sub: 0 };
  return {
    year: parseInt(m[1], 10),
    main: parseInt(m[2], 10),
    sub: m[3] ? parseInt(m[3], 10) : 0
  };
}

const items = $input.all();

items.sort((a, b) => {
  const ja = a.json || {};
  const jb = b.json || {};

  const na = parseVorgangsnummer(ja.vorgangsnummer);
  const nb = parseVorgangsnummer(jb.vorgangsnummer);

  if (na.year !== nb.year) return na.year - nb.year;
  if (na.main !== nb.main) return na.main - nb.main;
  if (na.sub !== nb.sub) return na.sub - nb.sub;

  const va = parseVolfdnr(ja.volfdnr);
  const vb = parseVolfdnr(jb.volfdnr);
  if (va !== vb) return va - vb;

  const fa = parseDate(ja.firstseen);
  const fb = parseDate(jb.firstseen);
  if (fa !== fb) return fa - fb;

  return safe(ja.vorgangKey).localeCompare(safe(jb.vorgangKey));
});

return items;

// Prüft, ob die veröffentlichungsnahen Kerntexte tatsächlich vorhanden sind.
const j = $input.item.json || {};
const errors = Array.isArray(j.contentValidationErrors)
  ? j.contentValidationErrors.filter(Boolean)
  : [];

const required = [
  ['websiteHeadline', 5],
  ['websiteArticle', 100],
  ['facebookPost', 80],
  ['instagramCaption', 50]
];

for (const [field, minLength] of required) {
  const value = String(j[field] || '').trim();
  if (value.length < minLength && !errors.some(e => String(e).includes(field))) {
    errors.push(field + ' fehlt oder ist zu kurz');
  }
}

const contentReady =
  j.contentParseError !== true &&
  j.contentValid !== false &&
  errors.length === 0;

let contentObj = {};
try {
  contentObj = typeof j.contentJson === 'string'
    ? JSON.parse(j.contentJson || '{}')
    : (j.contentJson || {});
} catch (e) {
  contentObj = {};
}

contentObj.workflow = {
  ...(contentObj.workflow && typeof contentObj.workflow === 'object'
    ? contentObj.workflow
    : {}),
  contentValid: contentReady,
  contentValidationErrors: errors,
  gateCheckedAt: new Date().toISOString(),
  workflowVersion: 'content-v24-schema-aligned'
};

return [{
  json: {
    ...j,
    contentReady,
    contentValid: contentReady,
    contentValidationErrors: errors,
    contentJson: JSON.stringify(contentObj),
    status: contentReady ? 'content_generated' : 'content_error',
    visualStatus: contentReady
      ? 'needs_visual_prompt'
      : 'blocked_by_content_error',
    visualNeeded: contentReady ? j.visualNeeded : false,
    visualDecisionReason: contentReady
      ? (j.visualDecisionReason || '')
      : 'Content-Gate blockiert: ' + (errors.join(' | ') || 'unbekannter Contentfehler')
  }
}];

// ============================================================
// SOURCE-LOCK PRÜFEN – V25.6
// Stellt nach Nextcloud/Tika den ursprünglichen Datenbankkontext wieder her.
// ============================================================

const current = $input.item.json || {};
function safeStr(v) { return v === null || v === undefined ? '' : String(v).trim(); }
function parseObj(v) {
  if (!v) return {};
  if (typeof v === 'object' && !Array.isArray(v)) return v;
  try { const p = JSON.parse(String(v)); return p && typeof p === 'object' && !Array.isArray(p) ? p : {}; }
  catch (e) { return {}; }
}
function asArr(v) {
  if (Array.isArray(v)) return v.filter(Boolean).map(x => safeStr(x));
  if (typeof v === 'string' && v.trim()) {
    try { const p = JSON.parse(v); if (Array.isArray(p)) return p.filter(Boolean).map(x => safeStr(x)); } catch (e) {}
  }
  return [];
}
function usable(v) {
  if (v === null || v === undefined) return false;
  if (typeof v === 'object' && !Array.isArray(v)) return Object.keys(v).length > 0;
  const s = safeStr(v);
  return s !== '' && s !== '{}' && s !== 'null' && s !== 'undefined';
}
function nodeItems(name) {
  try { const a = $(name).all(0, $runIndex); return Array.isArray(a) ? a : []; }
  catch (e) { return []; }
}

const currentKey = safeStr(current.vorgangKey);
let original = {};
for (const name of ['Loop Reaktions-Vorgänge', 'Code in JavaScript', 'Prüfe Content-Freigabe']) {
  const items = nodeItems(name);
  if (!items.length) continue;
  const match = currentKey ? items.find(x => safeStr(x?.json?.vorgangKey) === currentKey) : items[0];
  if (match?.json) { original = match.json; break; }
}

const j = { ...original, ...current };
if (!usable(current.analysisJson)) j.analysisJson = original.analysisJson || '{}';
if (!safeStr(current.vorgangKey)) j.vorgangKey = original.vorgangKey || '';
if (!safeStr(current.vorgangsnummer)) j.vorgangsnummer = original.vorgangsnummer || '';
if (!safeStr(current.title)) j.title = original.title || '';
if (!safeStr(current.summaryText)) j.summaryText = original.summaryText || '';

const analysis = parseObj(j.analysisJson);
const sl = parseObj(analysis.sourceLock);
const slValid = analysis.sourceLockValid === true || safeStr(analysis.sourceLockValid).toLowerCase() === 'true';
const errors = [];
if (!safeStr(sl.sourceTopic)) errors.push('sourceTopic fehlt');
if (!safeStr(sl.sourceConflict)) errors.push('sourceConflict fehlt');
if (asArr(sl.requiredTerms).length < 2) errors.push('requiredTerms enthält weniger als 2 Begriffe');
if (!slValid) errors.push('analysisJson.sourceLockValid ist nicht true');

return {
  json: {
    ...j,
    _sourceLockOk: errors.length === 0,
    _sourceLockError: errors.length ? 'Source-Lock nicht gültig: ' + errors.join('; ') : '',
    _sourceLockRestoredFromOriginal: !usable(current.analysisJson) && usable(original.analysisJson)
  }
};

// V25.7: Source-Lock blockiert Content - vorhandene Content-Felder NICHT leeren
// WICHTIG: Dieser Node läuft im Modus "Run Once for Each Item" und muss ein einzelnes Item-Objekt zurückgeben, kein Array.
const j = $input.item.json || {};
return {
  json: {
    ...j,
    // Nur Status- und Fehlerfelder setzen, vorhandene Content-Felder erhalten
    contentParseError: true,
    contentValid: false,
    contentValidationErrors: ['Source-Lock nicht gültig: ' + (j._sourceLockError || 'unbekannter Fehler')],
    // contentJson NICHT auf '{}' setzen wenn bereits Inhalt vorhanden
    contentJson: (j.contentJson && j.contentJson !== '{}' && j.contentJson !== 'null') ? j.contentJson : '{}',
    // Content-Felder NICHT überschreiben wenn bereits vorhanden
    websiteHeadline: j.websiteHeadline || '',
    websiteArticle: j.websiteArticle || '',
    facebookPost: j.facebookPost || '',
    pressStatement: j.pressStatement || '',
    instagramCaption: j.instagramCaption || '',
    status: 'needs_content',
    visualStatus: 'blocked_by_source_lock',
    visualNeeded: j.visualNeeded || false,
    visualDecisionReason: 'Content blockiert durch ungültigen Source-Lock: ' + (j._sourceLockError || ''),
    textExtractionError: 'Source-Lock nicht gültig: ' + (j._sourceLockError || '')
  }
};

// V25.7: Content-Freigabe mit positiver Whitelist
// WICHTIG: Dieser Node läuft im Modus "Run Once for Each Item" und muss ein einzelnes Item-Objekt zurückgeben, kein Array.
const j = $input.item.json || {};
function safeStr(v) { return v === null || v === undefined ? '' : String(v).trim(); }

const visualStatus = safeStr(j.visualStatus);
const status = safeStr(j.status);

// Positive Whitelist - NUR diese exakten Werte sind erlaubt.
// blocked_by_content_error bleibt ein Fehlerstatus und wird nicht normal weiterverarbeitet.
// Bereits falsch hängende Datensätze werden separat durch den Reparaturzweig geheilt.
// visual_topic_error blockiert bewusst nur das Sharepic (P2/P3), nicht die Text-Content-
// Erstellung hier - sonst bleiben sachlich unbedenkliche Vorgänge (z.B. weil das Bild-Motiv
// sensible Betroffene zeigen würde) für immer bei needs_content haengen, ohne dass je ein
// Website-/Facebook-/Pressetext entsteht.
const ALLOWED_VISUAL_STATUS = new Set(['waiting_for_content', 'no_visual', 'visual_topic_error', 'visual_topic_ok']);

const isAllowed = status === 'needs_content' && ALLOWED_VISUAL_STATUS.has(visualStatus);

return {
  json: {
    ...j,
    _contentFreigabe: isAllowed,
    _contentFreigabeReason: isAllowed
      ? 'freigegeben (status=' + status + ', visualStatus=' + visualStatus + ')'
      : ('nicht freigegeben: status=' + status + ', visualStatus=' + (visualStatus || '(leer)'))
  }
};

// V25.7 Reparaturzweig: heilt alte Statusbrüche aus früheren Läufen.
// Problemzustand: status=content_posted/content_generated, aber visualStatus=blocked_by_content_error.
// Wenn Content fertig ist und SourceLock+VisualAnchors gültig sind, wird der Datensatz wieder in den Visual-Prompt-Bau gegeben.

function safe(v) { return v === null || v === undefined ? '' : String(v).trim(); }
function norm(v) { return safe(v).toUpperCase(); }
function num(v) {
  const n = parseFloat(safe(v).replace(',', '.'));
  return Number.isFinite(n) ? n : 0;
}
function bool(v) {
  if (v === true || v === 1) return true;
  if (v === false || v === 0 || v === null || v === undefined) return false;
  const s = String(v).trim().toLowerCase();
  return s === 'true' || s === '1' || s === 'yes';
}
function parseObj(v) {
  if (!v) return {};
  if (typeof v === 'object' && !Array.isArray(v)) return v;
  try {
    const p = JSON.parse(String(v));
    return p && typeof p === 'object' && !Array.isArray(p) ? p : {};
  } catch (e) { return {}; }
}
function asArr(v) {
  if (Array.isArray(v)) return v.filter(Boolean).map(x => safe(x)).filter(Boolean);
  if (typeof v === 'string' && v.trim()) {
    try {
      const p = JSON.parse(v);
      if (Array.isArray(p)) return p.filter(Boolean).map(x => safe(x)).filter(Boolean);
    } catch (e) {}
    return String(v).split(/\s*\|\s*|\s*;\s*/).map(x => safe(x)).filter(Boolean);
  }
  return [];
}

const repaired = [];

for (const item of $input.all()) {
  const j = item.json || {};
  const status = safe(j.status);
  const visualStatus = safe(j.visualStatus);

  if (!['content_posted', 'content_generated'].includes(status)) continue;
  if (!['blocked_by_content_error', 'waiting_for_content'].includes(visualStatus)) continue;

  const analysis = parseObj(j.analysisJson);
  const sl = parseObj(analysis.sourceLock);
  const va = parseObj(analysis.visualAnchors);

  const sourceLockOk =
    bool(analysis.sourceLockValid) &&
    safe(sl.sourceTopic) &&
    safe(sl.sourceConflict) &&
    asArr(sl.requiredTerms).length >= 2 &&
    asArr(sl.requiredObjects).length >= 2 &&
    safe(sl.requiredAction);

  const anchorsOk =
    bool(analysis.visualAnchorsValid) &&
    safe(va.satireThemaKonkret) &&
    safe(va.satireKonfliktKonkret) &&
    asArr(va.visualPflichtobjekte).length >= 2 &&
    safe(va.visualPflichthandlung) &&
    safe(va.visualErkennungssatz) &&
    safe(va.visualUeberzeichnung);

  const sprengstoff = norm(j.sprengstoff || analysis.sprengstoff);
  const empfehlung = norm(j.empfehlung || analysis.empfehlung);
  const relevantScore = num(j.relevantScore || analysis.relevantScore || analysis.relevanz);
  const kommunikationspotenzial = num(j.kommunikationspotenzial || analysis.kommunikationspotenzial);

  const visualRequested =
    bool(j.visualNeeded) ||
    bool(j.instagramSharepicNoetig) ||
    bool(analysis.instagramSharepicNoetig) ||
    (empfehlung === 'REAGIEREN' && ['MITTEL', 'HOCH'].includes(sprengstoff)) ||
    relevantScore >= 8 ||
    kommunikationspotenzial >= 8;

  if (!sourceLockOk || !anchorsOk || !visualRequested) continue;

  const contentObj = parseObj(j.contentJson);
  contentObj.workflow = {
    ...(contentObj.workflow && typeof contentObj.workflow === 'object' ? contentObj.workflow : {}),
    contentValid: true,
    visualRequested: true,
    visualReleased: true,
    visualStatus: 'needs_visual_prompt',
    visualDecisionReason: 'V25.7 Reparatur: Content ist fertig; alter blocked_by_content_error wurde überschrieben; SourceLock+VisualAnchors gültig',
    visualStatusRepairedAt: new Date().toISOString(),
    workflowVersion: 'content-v25.7-visual-status-repair-fix'
  };

  repaired.push({
    json: {
      ...j,
      contentJson: JSON.stringify(contentObj),
      visualStatus: 'needs_visual_prompt',
      visualNeeded: true,
      instagramSharepicNoetig: true,
      visualDecisionReason: 'V25.7 Reparatur: Content vorhanden, Bewertung bildwürdig, SourceLock und VisualAnchors gültig',
      // Alte Bildfelder zurücksetzen, damit der Visual Prompt Builder sauber neu baut.
      imagePrompt: '',
      imageHeadline: '',
      imageSubline: '',
      imageNegativePrompt: '',
      visualJson: '{}'
    }
  });
}

return repaired;

// Baut eine Matrix-Sammelmeldung für dauerhaft blockierte Vorgänge
// (visualStatus = blocked_by_source_lock oder visual_topic_error).
// Anders als blocked_by_content_error/waiting_for_content gibt es für diese beiden
// Zustände keinen automatischen Repair-Mechanismus - ohne diese Meldung bleiben
// sie unbemerkt liegen, bis jemand manuell in die Data Table schaut.

function safeStr(v) { return v === null || v === undefined ? '' : String(v).trim(); }

if (!items || items.length === 0) {
  return [];
}

const zeilen = items.map(item => {
  const j = item.json || {};
  return `• ${safeStr(j.vorgangsnummer) || '?'} – ${safeStr(j.title) || '(kein Titel)'}\n  Status: ${safeStr(j.visualStatus)}\n  Grund: ${safeStr(j.visualDecisionReason) || '(kein Grund hinterlegt)'}\n  ${safeStr(j.allrisUrl)}`;
});

const msg = `⚠️ Dauerhaft blockierte Visual-Vorgänge (${items.length})\n\n` +
  `Diese Vorgänge werden vom Repair-Mechanismus nicht automatisch erneut versucht ` +
  `und benötigen manuelle Prüfung:\n\n` +
  zeilen.join('\n\n');

const txnId = 'blkalert_' + Date.now();

return [{ json: { alertMessage: msg, txnId, blockedCount: items.length } }];
